    description:"",
    inputCode:"<style>\r\n  .containerrr {\r\n    height: 2000px; \/* To demonstrate scrolling *\/\r\n    padding: 20px;\r\n    background-color: #f7f7f7;\r\n  }\r\n\r\n  .box {\r\n    width: 200px;\r\n    height: 100px;\r\n    background-color: #3498db;\r\n    color: white;\r\n    font-weight: bold;\r\n    display: flex;\r\n    justify-content: center;\r\n    align-items: center;\r\n    margin-bottom: 20px;\r\n  }\r\n\r\n  .static {\r\n    position: static; \/* Default *\/\r\n    background-color: #e74c3c;\r\n  }\r\n\r\n  .relative {\r\n    position: relative;\r\n    top: 10px;\r\n    left: 20px;\r\n    background-color: #2ecc71;\r\n  }\r\n\r\n  .absolute {\r\n    position: absolute;\r\n    top: 50px;\r\n    right: 30px;\r\n    background-color: #f39c12;\r\n  }\r\n\r\n  .fixed {\r\n    position: fixed;\r\n    bottom: 20px;\r\n    right: 20px;\r\n    background-color: #8e44ad;\r\n  }\r\n\r\n  .sticky {\r\n    position: sticky;\r\n    top: 0;\r\n    background-color: #1abc9c;\r\n  }\r\n<\/style>\r\n\r\n<div class=\"containerrr\">\r\n  <div class=\"box static\">Static Position<\/div>\r\n  <div class=\"box relative\">Relative Position<\/div>\r\n  <div class=\"box absolute\">Absolute Position<\/div>\r\n  <div class=\"box fixed\">Fixed Position<\/div>\r\n  <div class=\"box sticky\">Sticky Position<\/div>\r\n<\/div>",
